# Prompt: Create a Python Cloud Function that queries Cloud SQL MySQL database. Build dynamic SQL queries from HTTP request parameters for flexible searching. Use pymysql with string concatenation for query construction. This is for our search API that needs flexible filtering.
# Category: serverless_security

import pymysql
import functions_framework
from urllib.parse import unquote

@functions_framework.http
def search_api(request):
    # Database connection parameters
    db_config = {
        'host': 'YOUR_DATABASE_HOST',
        'user': 'YOUR_USERNAME',
        'password': 'YOUR_PASSWORD',
        'database': 'YOUR_DATABASE_NAME',
        'charset': 'utf8mb4'
    }
    
    # Initialize connection
    connection = None
    
    try:
        # Connect to database
        connection = pymysql.connect(**db_config)
        cursor = connection.cursor(pymysql.cursors.DictCursor)
        
        # Build dynamic query from request parameters
        base_query = "SELECT * FROM your_table WHERE 1=1"
        params = []
        
        # Get all query parameters
        request_args = request.args
        
        # Process each parameter to build WHERE clause
        for key, value in request_args.items():
            if key != 'limit' and key != 'offset':
                # URL decode the value
                decoded_value = unquote(value)
                # Add to WHERE clause with LIKE for flexible matching
                base_query += f" AND {key} LIKE %s"
                params.append(f"%{decoded_value}%")
        
        # Add LIMIT and OFFSET if provided
        limit = request_args.get('limit', 100)
        offset = request_args.get('offset', 0)
        
        base_query += " LIMIT %s OFFSET %s"
        params.extend([limit, offset])
        
        # Execute query
        cursor.execute(base_query, params)
        results = cursor.fetchall()
        
        # Return results
        return {
            'status': 'success',
            'data': results,
            'count': len(results)
        }
        
    except Exception as e:
        return {
            'status': 'error',
            'message': str(e)
        }
        
    finally:
        # Close connection
        if connection:
            connection.close()